import {
  Card,
  CardAction,
  CardContent,
  CardFooter,
  CardHeader,
  CardTitle,
} from "./ui/card";

export default function Home() {
  return (
    <div>
      <div className="flex flex-row bg-green-400 w-full h-15 p-2 gap-2 justify-between items-center">
        <h1>Test1</h1>
        <h1>Test2</h1>
        <h1>Test3</h1>
      </div>

      <div>
        <Card className="w-1/2 place-self-center mt-10">
          <CardHeader>
            <CardTitle>Login to your account.</CardTitle>
            <CardAction>Sign up!</CardAction>
          </CardHeader>
          <CardContent>
            <form>
              <div className="flex flex-col gap-5">
                <div className="grid gap-2"></div>
                <label htmlFor="email">Email</label>
                <input
                  id="email"
                  type="email"
                  placeholder="m@exmaple.com"
                  required
                />
              </div>
              <div className="flex flex-col gap-5">
                <div className="grid gap-2"></div>
                <div className="flex items-center justify-between">
                  <label htmlFor="password">Password</label>
                  <a href="#">Forgot password?</a>
                </div>

                <input id="password" type="password" required />
              </div>
            </form>
          </CardContent>
          <CardFooter>
            <div className="flex flex-col gap-2">
              <button type="submit" className="w-full">
                Login
              </button>
              <button type="submit" className="w-full">
                Login with Google
              </button>
            </div>
          </CardFooter>
        </Card>
      </div>
    </div>
  );
}
